mapper.update:
UPDATE tb_union_subject

    code=#{code},
    name=#{name},
    parent_code=#{parentCode},
    level=#{level}

WHERE id=#{id}

mapper.select:
SELECT id,code,name,parent_code parentCode,level,create_time createTime FROM tb_union_subject
and code LIKE CONCAT('%',#{query.code},'%') and name LIKE CONCAT('%',#{query.name},'%')
ORDER BY LPAD(code,12,'0') LIMIT #{offset},#{pageSize}
